import React, { useEffect, useState, useRef } from 'react';
import { GatsbyImage } from 'gatsby-plugin-image';
import Box from '@mui/material/Box';

const Mainvisual = data => {
  const img = data.images.allFile.edges;

  const containerRef = useRef(null);

  const [clientHeight, setClientHeight] = useState(
    document.documentElement.clientHeight
  );

  const [current, setCurrent] = useState(
    Math.floor(Math.random() * img.length)
  );

  const [willShow, setWillShow] = useState(true);

  const onTransitionEnd = () => {
    if (!willShow) {
      // 消えた時の処理
      const _current = (current + 1) % img.length;

      setCurrent(_current);

      setTimeout(() => {
        console.log('timeout');
        setWillShow(true);
      }, 100);
    } else {
      // @TODO
      setTimeout(() => {
        setWillShow(false);
      }, 3500);
    }
  };

  useEffect(() => {
    const update = () => {
      const { width, height } =
        img[current].node.childImageSharp.gatsbyImageData;

      const aspectRatio = width / height;

      // ヘッダーの2倍を引き適切なアスペクト比に
      const newWidth = (clientHeight - 160) * aspectRatio;
      containerRef.current.style.width = newWidth + 'px';
    };

    const updateClientHeight = () => {
      setClientHeight(document.documentElement.clientHeight);
    };

    window.addEventListener('resize', updateClientHeight);
    window.addEventListener('load', updateClientHeight);

    updateClientHeight();
    update();

    return () => {
      window.removeEventListener('resize', updateClientHeight);
      window.removeEventListener('load', updateClientHeight);
    };
  }, [img, current, clientHeight]);

  return (
    <Box
      component='section'
      sx={{
        position: 'relative',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        width: '100%',
        mt: 10,
        height: 'calc(100vh - 160px)',
        height: 'calc(100dvh - 160px)'
      }}
    >
      <Box
        ref={containerRef}
        sx={{
          position: 'relative',
          height: '100%',
          overflow: 'hidden'
        }}
      >
        <Box
          onTransitionEnd={onTransitionEnd}
          sx={{
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            zIndex: 5,
            transition: 'opacity 1000ms ease-out',
            opacity: willShow ? 1 : 0
          }}
        >
          <GatsbyImage
            image={img[current].node.childImageSharp.gatsbyImageData}
            alt='YUHEI ONO'
            layout='fullWidth'
            placeholder='blurred'
          />
        </Box>
        <Box
          sx={{
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            zIndex: -1
          }}
        >
          <GatsbyImage
            image={
              img[(current + 1) % img.length].node.childImageSharp
                .gatsbyImageData
            }
            alt='preload'
            layout='fullWidth'
            style={{
              opacity: 0,
              visibility: 'hidden'
            }}
          />
        </Box>
      </Box>
    </Box>
  );
};

export default Mainvisual;
